BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE user_id INT;
    DECLARE cur CURSOR FOR SELECT user_id FROM users WHERE status = 'Inactive';
    DECLARE CONTINUE HANDLER FOR INSERT INTO status_log user_id = user_id;

    OPEN cur;
    read_loop: LOOP
        FETCH cur INTO user_id;
        IF done THEN
            LEAVE read_loop;
        END IF;
        BEGIN
            -- delete record from users
            DELETE FROM users WHERE user_id = user_id;
            -- insert into status_log
            INSERT INTO status_log (user_id, status, modification_date)
            VALUES (user_id, 'Inactive', NOW());
        END;
    END LOOP;
    CLOSE cur;
END //
